<template>
  <div>
    <DisplayEmptyBall v-if="status < 2" :lang="lang" :length="length" />
    <DisplaySpinBalls v-else-if="status===2" :lang="lang" :length="length" :wait="waiting" :end-time="endTime" :result="result" />
    <DisplayResultBalls v-else-if="status===3" :lang="lang" :result="result" />
  </div>
</template>
<script>
import DisplayEmptyBall from './DisplayEmptyBall.vue'
import DisplaySpinBalls from './DisplaySpinBalls.vue'
import DisplayResultBalls from './DisplayResultBalls.vue'

export default {
  name: 'Show1StSpin',
  components: {
    DisplayEmptyBall,
    DisplaySpinBalls,
    DisplayResultBalls
  },
  props: {
    lang: {
      type: String,
      required: true
    },
    length: {
      type: [Number, String],
      required: true
    },
    results: {
      type: [Object, String],
    },
    resultKey: {
      type: String
    },
    updateCode: {
      type: Number,
      default: null
    },
    startSpin: {
      type: String,
      default: null
    },
    startShow: {
      type: String,
      default: null
    },
    endTime: {
      type: String,
      default: null
    },
    slotCounting: {
      type: String,
      default: null
    },
    distance: {
      type: Number,
      default: 30
    }
  },
  data() {
    return {
      setTimeout: null,
      setTimeoutSpinNumber: null,
      step: null
    }
  },
  watch: {
    updateCode() {
      console.log('update process 1st', this.updateCode, this.slotCounting)
      // เคลียร์ timeout ก่อนหน้า
      clearTimeout(this.setTimeout)
      clearTimeout(this.setTimeoutSpinNumber)
      this.process()
    }
  },
  computed: {
    status() {
      return this.step
    },
    result() {
      if (this.results) {
        return this.results[this.resultKey]
      }else{
        return null
      }
    },
    waiting() {
      if(this.endTime) {
        let diff = this.$moment(this.endTime).diff(this.$moment(), 'milliseconds')
        return diff
      }else {
        return false
      }
    }
  },
  methods: {
    process() {
      // ยังไม่ถึงเวลาเริ่มหมุน
      if(this.$moment().isBefore(this.startSpin)) {
        this.step = 0
        // ตั้งค่า timeout เพื่อคำนวนสถานะอีกรอบ
        let diff = this.$moment(this.startSpin).diff(this.$moment(), 'milliseconds')
        this.setTimeout = setTimeout(() => {
          this.process()
        }, diff)
      }else
      // ถ้ารางวัลที่ 2 ยังไม่มี  และถึงเวลาออกผลแล้ว ให้หมุนต่อไป
      if(!this.results['prize_2nd'] && this.$moment().isAfter(this.endTime)) {
        console.log('ไม่มีผลรางวัลที่ 2')
        this.step = 2
      }else
      // ถึงเวลาออกผลรางวัลที่ 1 แล้ว แต่ยังไม่มีผล
      if(this.resultKey === 'prize_1st' && this.slotCounting === 'prize_1st' && !this.result) {
        console.log('ถึงเวลาออกผลรางวัลที่ 1 แล้ว แต่ยังไม่มีผล')
        this.step = 2
      }else
      // ออกผลเสร็จหมดแล้ว
      if(this.$moment().isAfter(this.endTime)) {
        this.step = 3
      }else
      // กำลังหมุน
      if(this.$moment().isAfter(this.startSpin)) {
        console.log('กำลังหมุน', this.slotCounting, this.resultKey, this.waiting, this.$moment())
        if (this.slotCounting === this.resultKey) {
          if(this.waiting !== false && this.result) {
            this.step = 2

            let wait = this.$moment(this.endTime).diff(this.$moment(), 'milliseconds') + 2000
            console.log('step 2', 'นับเวลาถอยหลังออกผลเสร็จ', wait, this.$moment())
            this.setTimeoutSpinNumber = setTimeout(() => {
              console.log('changeSlot...', this.$moment())
              this.$emit('changeSlot')
            }, wait)

          }else{
            this.step = 1
          }
        } else {
          this.step = 1
        }
      }
    }
  },
  mounted() {
    //this.process()
  },
  beforeDestroy() {
    clearTimeout(this.setTimeout)
    clearTimeout(this.setTimeoutSpinNumber)
  }
}
</script>
