<template>
  <div class="spin-numbers">
    <SlotBall v-for="(n, key) in numbers" v-bind:key="key" :lang="lang" :select="n" :timeout="wait-((numbers.length-key-1)*8000)" :start="key" :end-time="endTime" />
  </div>
</template>
<script>
import SlotBall from './SlotBall.vue'

export default {
  name: 'DisplaySpinBalls',
  components: {
    SlotBall
  },
  props: {
    lang: {
      type: String,
      required: true
    },
    length: {
      type: [Number, String],
      required: true
    },
    wait: {
      type: [Number, Boolean],
      default: 30000
    },
    endTime: {
      type: String,
      default: null
    },
    result: {
      type: String,
      default: null
    }
  },
  computed: {
    numbers() {
      if (this.result)
        return this.result.split('')

      return new Array(+this.length)
    }
  },
  watch: {
    wait() {
      console.log('wait change ...')
    }
  },
  created() {
    console.log('slot balls...', this.wait)
  }
}
</script>
