<template>
  <div class="spin-numbers">
    <div v-for="(n, index) in numbers" :key="index" class="number">
      <img :src="img(n)">
    </div>
  </div>
</template>
<script>
export default {
  name: 'DisplayResult',
  props: {
    lang: {
      type: String,
      required: true
    },
    result: {
      type: [Number, String],
      default: ''
    }
  },
  computed: {
    numbers() {
      return this.result.split('')
    }
  },
  methods: {
    img(number) {
      return require(`@/assets/theme/${this.lang}/${number}.png`)
    }
  }
}
</script>
