import api from "@/services/apiService"

class LottoService {

  getResults() {
    return new Promise((resolve, reject) => {
      api.get('result')
        .then(function(response) {
          resolve(response.data)
        })
        .catch(function(error) {
          reject(error)
        });
    });
  }

  getResult(draw) {
    return new Promise((resolve, reject) => {
      api.get('result?draw=' + (draw ? draw : ''))
        .then(function(response) {
          resolve(response.data)
        })
        .catch(function(error) {
          reject(error)
        });
    });
  }

  getDrawdates() {
    return new Promise((resolve, reject) => {
      api.get('drawdate')
        .then(function(response) {
          resolve(response.data)
        })
        .catch(function(error) {
          reject(error)
        });
    });
  }

  getHistories(lotto_type, date) {
    return new Promise((resolve, reject) => {
      api.get('history/' + lotto_type + '?date=' + date)
        .then(function(response) {
          resolve(response.data)
        })
        .catch(function(error) {
          reject(error)
        });
    });
  }

}

export default new LottoService();
